// Build the prospect report + an internal Slack summary from the calculator data.
const b = $input.first().json.body || {};
const calc = b.calculator || {};
const r = calc.results || {};
const tasks = (calc.tasks || []).map(t => `\u2022 ${t.name || 'Untitled'} \u2014 ${t.people} people \u00d7 ${t.hrs} hrs/wk @ A$${t.rate}/hr`).join('\n');

const html = `
<div style="font-family:Inter,Arial,sans-serif;max-width:560px;margin:0 auto;color:#1a2030">
  <h2 style="font-weight:600;letter-spacing:-.02em">Your savings snapshot</h2>
  <p>Hi ${b.name || 'there'}, here are the numbers from your Automation Builders calculator.</p>
  <table style="width:100%;border-collapse:collapse;margin:18px 0">
    <tr><td style="padding:10px 0;border-bottom:1px solid #e6e9f0;color:#5b6678">Value unlocked over 3 years</td><td style="padding:10px 0;border-bottom:1px solid #e6e9f0;text-align:right;font-weight:600">${r.threeYearValue || '-'}</td></tr>
    <tr><td style="padding:10px 0;border-bottom:1px solid #e6e9f0;color:#5b6678">Hours burned / year</td><td style="padding:10px 0;border-bottom:1px solid #e6e9f0;text-align:right;font-weight:600">${r.hoursPerYear || '-'}</td></tr>
    <tr><td style="padding:10px 0;border-bottom:1px solid #e6e9f0;color:#5b6678">Cost / year</td><td style="padding:10px 0;border-bottom:1px solid #e6e9f0;text-align:right;font-weight:600">${r.costPerYear || '-'}</td></tr>
    <tr><td style="padding:10px 0;color:#5b6678">5-year cost of inaction</td><td style="padding:10px 0;text-align:right;font-weight:600">${r.fiveYearCost || '-'}</td></tr>
  </table>
  <p style="color:#5b6678;font-size:14px">Processes you entered:<br>${(tasks || '').replace(/\n/g,'<br>')}</p>
  <p style="margin-top:22px"><a href="https://calendly.com/noah-automationbuilders/30min" style="background:#7c5cff;color:#fff;text-decoration:none;padding:12px 22px;border-radius:10px;display:inline-block;font-weight:600">Book a 30-min call \u2192</a></p>
  <p style="color:#9aa3b2;font-size:12px;margin-top:24px">Automation Builders \u00b7 support@automationbuilders.ai</p>
</div>`;

const slackText = `:inbox_tray: *Report requested* \u2014 ${b.name || '-'} <${b.email || '-'}>\n3-yr value: ${r.threeYearValue || '-'} \u00b7 ${r.processCount || 0} process(es) \u00b7 ${r.hoursPerYear || '-'} hrs/yr`;

return [{ json: { to: b.email, name: b.name, subject: 'Your Automation Builders savings report', html, slackText } }];
